import { PageContainer } from '@ant-design/pro-components';
import { Card, Form, Input, Button, message, Tabs, Switch, Space, Divider } from 'antd';
import { useState, useEffect } from 'react';
import { request } from '@umijs/max';
import { SaveOutlined, ReloadOutlined } from '@ant-design/icons';

const { TabPane } = Tabs;

export default function Settings() {
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  // 获取设置
  const fetchSettings = async () => {
    try {
      setLoading(true);
      const res = await request('/api/v1/admin/settings');
      if (res.code === 200 && res.data) {
        // 将设置数据转换为表单值
        const formValues: any = {};
        Object.keys(res.data).forEach((key) => {
          formValues[key] = res.data[key].value;
        });
        form.setFieldsValue(formValues);
      }
    } catch (error) {
      message.error('获取设置失败');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchSettings();
  }, []);

  // 保存设置
  const handleSave = async (values: any) => {
    try {
      setSaving(true);
      const res = await request('/api/v1/admin/settings', {
        method: 'PUT',
        data: values,
      });
      if (res.code === 200) {
        message.success('设置已保存');
      } else {
        message.error(res.message || '保存失败');
      }
    } catch (error) {
      message.error('保存失败');
    } finally {
      setSaving(false);
    }
  };

  return (
    <PageContainer title="系统设置">
      <Card loading={loading}>
        <Form
          form={form}
          layout="vertical"
          onFinish={handleSave}
          initialValues={{
            site_name: '犬兜行',
            site_description: '带宠出行，探索世界',
          }}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="基础设置" key="basic">
              <Form.Item
                name="site_name"
                label="网站名称"
                rules={[{ required: true, message: '请输入网站名称' }]}
              >
                <Input placeholder="请输入网站名称" />
              </Form.Item>

              <Form.Item name="site_logo" label="网站Logo">
                <Input placeholder="Logo URL" />
