import { PageContainer, ProTable } from '@ant-design/pro-components';
import { Tag, Button, Space, message } from 'antd';
import { useRef } from 'react';
import { request } from '@umijs/max';
import dayjs from 'dayjs';
import { ReloadOutlined } from '@ant-design/icons';

const moduleMap: Record<string, string> = {
  user: '用户',
  route: '路线',
  order: '订单',
  schedule: '排期',
  pet: '宠物',
  traveler: '出行人',
  setting: '设置',
};

const actionMap: Record<string, { text: string; color: string }> = {
  CREATE: { text: '创建', color: 'green' },
  UPDATE: { text: '更新', color: 'blue' },
  DELETE: { text: '删除', color: 'red' },
  LOGIN: { text: '登录', color: 'cyan' },
  LOGOUT: { text: '登出', color: 'default' },
  QUERY: { text: '查询', color: 'default' },
  EXPORT: { text: '导出', color: 'purple' },
  REFUND: { text: '退款', color: 'orange' },
};

export default function OperationLogs() {
  const tableRef = useRef<any>(null);

  const columns = [
    {
      title: 'ID',
      dataIndex: 'id',
      width: 60,
      search: false,
    },
    {
      title: '操作人',
      width: 120,
      render: (record: any) => (
        <span>
          {record.username || `用户${record.user_id}`}
        </span>
      ),
    },
    {
      title: '模块',
      dataIndex: 'module',
      width: 100,
      valueEnum: {
        user: { text: '用户' },
        route: { text: '路线' },
        order: { text: '订单' },
        schedule: { text: '排期' },
        pet: { text: '宠物' },
        traveler: { text: '出行人' },
        setting: { text: '设置' },
      },
      render: (module: string) => moduleMap[module] || module,
    },
    {
      title: '操作',
      dataIndex: 'action',
      width: 100,
      valueEnum: {
        CREATE: { text: '创建' },
        UPDATE: { text: '更新' },
        DELETE: { text: '删除' },
        LOGIN: { text: '登录' },
        LOGOUT: { text: '登出' },
        QUERY: { text: '查询' },
        EXPORT: { text: '导出' },
        REFUND: { text: '退款' },
      },
      render: (action: string) => {
        const config = actionMap[action] || { text: action, color: 'default' };
        return <Tag color={config.color}>{config.text}</Tag>;
      },
    },
    {
      title: '描述',
      dataIndex: 'description',
      ellipsis: true,
      width: 250,
    },
    {
      title: '请求',
      width: 150,
      search: false,
      render: (record: any) => (
        <span style={{ fontSize: 12, color: '#666' }}>
          {record.request_method} {record.request_path}
        </span>
      ),
    },
    {
      title: '状态',
      dataIndex: 'response_code',
      width: 80,
      search: false,
      render: (code: number) => (
        <Tag color={code === 200 ? 'success' : 'error'}>
          {code || '-'}
        </Tag>
      ),
    },
    {
      title: 'IP地址',
      dataIndex: 'ip_address',
      width: 120,
      search: false,
    },
    {
      title: '时间',
      dataIndex: 'created_at',
      width: 180,
      search: false,
      render: (date: string) => date ? dayjs(date).format('YYYY-MM-DD HH:mm:ss') : '-',
    },
  ];

  return (
    <PageContainer
      title="操作日志"
      extra={
        <Button icon={<ReloadOutlined />} onClick={() => tableRef.current?.reload()}>
          刷新
        </Button>
      }
    >
      <ProTable
        columns={columns}
        actionRef={tableRef}
        request={async (params) => {
          const res = await request('/api/v1/admin/operation-logs', {
            params: {
              page: params.current,
              page_size: params.pageSize,
              user_id: params.user_id,
              module: params.module,
              action: params.action,
              start_date: params.start_date,
              end_date: params.end_date,
            },
          });
          return {
            data: res.data?.logs || [],
            success: res.code === 200,
            total: res.data?.total || 0,
          };
        }}
        rowKey="id"
        search={{ labelWidth: 'auto' }}
        pagination={{ pageSize: 20, showSizeChanger: true }}
        scroll={{ x: 1300 }}
      />
    </PageContainer>
  );
}

